  /**
   * The attachment point.
   * <p>
   * The lower subordination level, expressed as a decimal between 0 and 1.
   * Losses below this point are not covered by the tranche protection.
   */
  @PropertyDefinition(validate = "ArgChecker.inRange")
  private final double attachmentPoint;
  /**
   * The detachment point.
   * <p>
   * The upper subordination level, expressed as a decimal between 0 and 1.
   * Losses above this point are not covered by the tranche protection.
   * Must be greater than the attachment point.
