package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.google.common.collect.ImmutableMap;
import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.collect.tuple.Triple;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCds;
import com.opengamma.strata.product.credit.ResolvedCdsIndex;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranche based on ISDA standard model.
 * <p>
 * The CDS tranche is priced using the homogeneous pool assumption, where the underlying
 * CDS index is treated as a single name CDS with an adjusted notional based on the
 * tranche attachment and detachment points.
 * <p>
 * The tranche protection is only triggered when the cumulative losses exceed the
 * attachment point and absorbs losses up to the detachment point.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The pricer for single name CDS.
   */
  private final IsdaCdsProductPricer underlyingPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.underlyingPricer = new IsdaCdsProductPricer(formula);
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return underlyingPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the price of the CDS tranche product.
   * <p>
   * This method can calculate the clean or dirty price, see {@link PriceType}.
   * If calculating the clean price, the accrued interest is calculated based on the step-in date.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsIndex underlyingIndex = cdsTranche.getUnderlyingIndex();
    ResolvedCds cds = underlyingIndex.toSingleNameCds();

    // Compute price of the underlying CDS index
    double indexPrice = underlyingPricer.price(cds, ratesProvider, referenceDate, priceType, refData);

    // Apply tranche adjustment
    double attachmentPoint = cdsTranche.getAttachmentPoint();
    double detachmentPoint = cdsTranche.getDetachmentPoint();
    double trancheWidth = detachmentPoint - attachmentPoint;

    // Price is adjusted for tranche participation
    return indexPrice * trancheWidth;
  }

  /**
   * Calculates the price sensitivity of the product.
   * <p>
   * The price sensitivity of the product is the sensitivity of price to the underlying curves.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public com.opengamma.strata.market.sensitivity.PointSensitivityBuilder priceSensitivity(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ResolvedCdsIndex underlyingIndex = cdsTranche.getUnderlyingIndex();
    ResolvedCds cds = underlyingIndex.toSingleNameCds();

    // Compute sensitivity from the underlying index
    com.opengamma.strata.market.sensitivity.PointSensitivityBuilder baseSensitivity =
        underlyingPricer.priceSensitivity(cds, ratesProvider, referenceDate, refData);

    // Apply tranche adjustment
    double trancheWidth = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();

    return baseSensitivity.multipliedBy(trancheWidth);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche product.
   * <p>
   * The present value of the product is based on {@code referenceDate}.
   * This is typically the valuation date, or cash settlement date if the product is associated with a Trade.
   * <p>
   * This method can calculate the clean or dirty present value, see {@link PriceType}.
   * If calculating the clean value, the accrued interest is calculated based on the step-in date.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsIndex underlyingIndex = cdsTranche.getUnderlyingIndex();

    if (isExpired(underlyingIndex, ratesProvider)) {
      return CurrencyAmount.of(underlyingIndex.getCurrency(), 0d);
    }

    ResolvedCds cds = underlyingIndex.toSingleNameCds();
    LocalDate stepinDate = cds.getStepinDateOffset().adjust(ratesProvider.getValuationDate(), refData);
    LocalDate effectiveStartDate = cds.calculateEffectiveStartDate(stepinDate);
    double recoveryRate = underlyingPricer.recoveryRate(cds, ratesProvider);
    Triple<CreditDiscountFactors, LegalEntitySurvivalProbabilities, Double> rates =
        reduceDiscountFactors(cds, ratesProvider);

    double protectionLeg = (1d - recoveryRate) *
        underlyingPricer.protectionFull(cds, rates.getFirst(), rates.getSecond(), referenceDate, effectiveStartDate);
    double rpv01 = underlyingPricer.riskyAnnuity(
        cds, rates.getFirst(), rates.getSecond(), referenceDate, stepinDate, effectiveStartDate, priceType);

    // Compute the amount with tranche adjustment
    double attachmentPoint = cdsTranche.getAttachmentPoint();
    double detachmentPoint = cdsTranche.getDetachmentPoint();
    double trancheWidth = detachmentPoint - attachmentPoint;

    // Adjusted notional for tranche
    double trancheNotional = cds.getNotional() * trancheWidth;

    double amount = cds.getBuySell().normalize(trancheNotional) * rates.getThird() *
        (protectionLeg - rpv01 * cds.getFixedRate());

    return CurrencyAmount.of(cds.getCurrency(), amount);
  }

  /**
   * Calculates the loss allocation for the tranche.
   * <p>
   * This computes the expected loss that would be absorbed by the tranche.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the expected loss in basis points
   */
  public double expectedLoss(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ResolvedCdsIndex underlyingIndex = cdsTranche.getUnderlyingIndex();

    if (isExpired(underlyingIndex, ratesProvider)) {
      return 0d;
    }

    ResolvedCds cds = underlyingIndex.toSingleNameCds();
    LocalDate stepinDate = cds.getStepinDateOffset().adjust(ratesProvider.getValuationDate(), refData);
    LocalDate effectiveStartDate = cds.calculateEffectiveStartDate(stepinDate);
    double recoveryRate = underlyingPricer.recoveryRate(cds, ratesProvider);
    Triple<CreditDiscountFactors, LegalEntitySurvivalProbabilities, Double> rates =
        reduceDiscountFactors(cds, ratesProvider);

    double protectionLeg = (1d - recoveryRate) *
        underlyingPricer.protectionFull(cds, rates.getFirst(), rates.getSecond(), referenceDate, effectiveStartDate);

    double attachmentPoint = cdsTranche.getAttachmentPoint();
    double detachmentPoint = cdsTranche.getDetachmentPoint();
    double trancheWidth = detachmentPoint - attachmentPoint;

    // Expected loss is the protection leg adjusted for tranche participation
    return protectionLeg * trancheWidth * 10000d;  // Convert to basis points
  }

  //-------------------------------------------------------------------------
  /**
   * Checks if the CDS index is expired.
   *
   * @param cdsIndex  the CDS index
   * @param ratesProvider  the rates provider
   * @return true if expired
   */
  private boolean isExpired(ResolvedCdsIndex cdsIndex, CreditRatesProvider ratesProvider) {
    return cdsIndex.getProtectionEndDate().isBefore(ratesProvider.getValuationDate());
  }

  /**
   * Reduces the discount factors for pricing.
   *
   * @param cds  the CDS
   * @param ratesProvider  the rates provider
   * @return the reduced discount factors
   */
  private Triple<CreditDiscountFactors, LegalEntitySurvivalProbabilities, Double> reduceDiscountFactors(
      ResolvedCds cds,
      CreditRatesProvider ratesProvider) {

    CreditDiscountFactors discountFactors = ratesProvider.discountFactors(cds.getCurrency());
    LegalEntitySurvivalProbabilities survivalProbabilities =
        ratesProvider.survivalProbabilities(cds.getLegalEntityId());
    double recoveryRate = underlyingPricer.recoveryRate(cds, ratesProvider);
    double factor = (1d - recoveryRate);

    return Triple.of(discountFactors, survivalProbabilities, factor);
  }
}

