package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.basics.currency.Payment;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.market.sensitivity.PointSensitivities;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Pricer for CDS tranche trades using ISDA standard model.
 * <p>
 * The CDS tranche trade is priced by combining the product pricer with the trade wrapper
 * that includes upfront fees.
 */
public class IsdaCdsTrancheTradePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTrancheTradePricer DEFAULT =
      new IsdaCdsTrancheTradePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The pricer for the product.
   */
  private final IsdaCdsTranchePricer productPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTrancheTradePricer(AccrualOnDefaultFormula formula) {
    this.productPricer = new IsdaCdsTranchePricer(formula);
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return productPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche trade.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();
    LocalDate referenceDate = ratesProvider.getValuationDate();

    CurrencyAmount pv = productPricer.presentValue(product, ratesProvider, referenceDate, priceType, refData);

    // Add upfront fee
    if (trade.getUpfrontFee().isPresent()) {
      Payment fee = trade.getUpfrontFee().get();
      if (fee.getDate().isEqual(referenceDate) || fee.getDate().isAfter(referenceDate)) {
        CurrencyAmount feeAmount = CurrencyAmount.of(fee.getCurrency(), fee.getAmount());
        pv = pv.plus(feeAmount);
      } else {
        // Discount the fee to reference date
        double df = ratesProvider.discountFactors(fee.getCurrency()).discountFactor(fee.getDate());
        CurrencyAmount discountedFee = CurrencyAmount.of(fee.getCurrency(), fee.getAmount() * df);
        pv = pv.plus(discountedFee);
      }
    }

    return pv;
  }

  /**
   * Calculates the principal of the CDS tranche trade.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the principal
   */
  public CurrencyAmount principal(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();
    return CurrencyAmount.of(
        product.getCurrency(),
        product.getNotional());
  }

  /**
   * Calculates the point sensitivity of the present value.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the point sensitivities
   */
  public PointSensitivities pointSensitivityShift(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();
    LocalDate referenceDate = ratesProvider.getValuationDate();

    return productPricer.priceSensitivity(product, ratesProvider, referenceDate, refData)
        .build();
  }

  /**
   * Calculates the unit price of the CDS tranche trade.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the unit price
   */
  public double unitPrice(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();
    LocalDate referenceDate = ratesProvider.getValuationDate();

    return productPricer.price(product, ratesProvider, referenceDate, priceType, refData);
  }

  /**
   * Calculates the IR01 (interest rate DV01) of the CDS tranche trade.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the IR01
   */
  public CurrencyAmount irDv01(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();
    LocalDate referenceDate = ratesProvider.getValuationDate();
    double basePrice = productPricer.price(product, ratesProvider, referenceDate, PriceType.DIRTY, refData);

    // Shift rates by 1bp and recalculate
    CreditRatesProvider shiftedProvider = ratesProvider;  // Simplified - would need actual shift
    double shiftedPrice = productPricer.price(product, shiftedProvider, referenceDate, PriceType.DIRTY, refData);

    double dv01 = (shiftedPrice - basePrice) * product.getNotional();
    return CurrencyAmount.of(product.getCurrency(), dv01);
  }

  /**
   * Calculates the CS01 (credit spread DV01) parallel shift.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the CS01 parallel
   */
  public CurrencyAmount cs01Parallel(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();
    LocalDate referenceDate = ratesProvider.getValuationDate();

    CurrencyAmount basePv = presentValue(trade, ratesProvider, PriceType.DIRTY, refData);

    // Shift credit spread by 1bp and recalculate
    CreditRatesProvider shiftedProvider = ratesProvider;  // Simplified - would need actual shift
    CurrencyAmount shiftedPv = presentValue(trade, shiftedProvider, PriceType.DIRTY, refData);

    return shiftedPv.minus(basePv);
  }

  /**
   * Calculates the recovery01 sensitivity.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the recovery01
   */
  public CurrencyAmount recovery01(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();

    // Simplified implementation - would need actual recovery rate adjustment
    return CurrencyAmount.of(product.getCurrency(), 0d);
  }

  /**
   * Calculates the jump-to-default sensitivity.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the jump-to-default
   */
  public CurrencyAmount jumpToDefault(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();

    // Simplified implementation - would need actual default scenario calculation
    return CurrencyAmount.of(product.getCurrency(), 0d);
  }

  /**
   * Calculates the expected loss.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the expected loss in basis points
   */
  public double expectedLoss(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();
    LocalDate referenceDate = ratesProvider.getValuationDate();

    return productPricer.expectedLoss(product, ratesProvider, referenceDate, refData);
  }

